inline ::flatbuffers::Offset<SensorReading> CreateSensorReading(
    ::flatbuffers::FlatBufferBuilder &_fbb,
    uint64_t timestamp = 0,
    ::flatbuffers::Offset<::flatbuffers::String> device_id = 0,
    double temp = 0.0,
    double humidity = 0.0,
    double pressure = 0.0,
    double accel_x = 0.0,
    double accel_y = 0.0,
    double accel_z = 0.0,
    double gyro_x = 0.0,
    double gyro_y = 0.0,
    double gyro_z = 0.0,
    double mag_x = 0.0,
    double mag_y = 0.0,
    double mag_z = 0.0,
    float battery = 0.0f,
    int16_t signal_dbm = 0,
    uint32_t error_code = 0,
    ::flatbuffers::Offset<::flatbuffers::String> firmware = 0) {
  SensorReadingBuilder builder_(_fbb);
  builder_.add_mag_z(mag_z);
  builder_.add_mag_y(mag_y);
  builder_.add_mag_x(mag_x);
  builder_.add_gyro_z(gyro_z);
  builder_.add_gyro_y(gyro_y);
  builder_.add_gyro_x(gyro_x);
  builder_.add_accel_z(accel_z);
  builder_.add_accel_y(accel_y);
  builder_.add_accel_x(accel_x);
  builder_.add_pressure(pressure);
  builder_.add_humidity(humidity);
  builder_.add_temp(temp);
  builder_.add_timestamp(timestamp);
  builder_.add_firmware(firmware);
  builder_.add_error_code(error_code);
  builder_.add_battery(battery);
  builder_.add_device_id(device_id);
  builder_.add_signal_dbm(signal_dbm);
  return builder_.Finish();
}

